1	<!DOCTYPE html>
2	<html lang="ko">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>우리WON카 — 비회원 AI 에이전트</title>
7	<style>
8	@import url("https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap");
9	*{box-sizing:border-box;margin:0;padding:0;}
10	body{font-family:"Noto Sans KR",sans-serif;background:#f4f5f7;font-size:13px;color:#111;}
11	
12	.topbar{height:36px;background:#f9f9f9;border-bottom:1px solid #e0e0e0;display:flex;align-items:center;justify-content:flex-end;padding:0 24px;gap:8px;font-size:12px;color:#555;}
13	.tb-guest{display:inline-flex;align-items:center;gap:5px;border:1px solid #ccc;border-radius:4px;padding:3px 10px;background:#fff;font-size:12px;color:#888;}
14	.tb-apply{background:#1a56db;color:#fff;border:none;border-radius:4px;padding:4px 14px;font-size:12px;font-weight:700;cursor:pointer;}
15	
16	.header{background:#fff;border-bottom:1px solid #e8e8e8;padding:10px 24px;display:flex;align-items:center;}
17	.logo{font-size:26px;font-weight:900;letter-spacing:-0.04em;color:#0a1628;margin-right:22px;}
18	.logo span{color:#1a56db;}
19	.search-bar{flex:1;max-width:500px;border:2px solid #cbd5e1;border-radius:24px;display:flex;align-items:center;padding:7px 18px;}
20	.search-bar input{border:none;outline:none;flex:1;font-size:13px;font-family:inherit;color:#333;}
21	.search-bar input::placeholder{color:#aaa;}
22	.hnav{margin-left:auto;display:flex;gap:24px;}
23	.hico{display:flex;flex-direction:column;align-items:center;gap:2px;cursor:pointer;font-size:11px;color:#666;}
24	.hico svg{width:22px;height:22px;}
25	
26	.page{display:flex;height:calc(100vh - 82px);overflow:hidden;}
27	.left{flex:1;overflow-y:auto;padding:18px 20px;}
28	.right{width:248px;min-width:248px;background:#fff;border-left:1px solid #e4e4e4;display:flex;flex-direction:column;}
29	
30	.banner{width:100%;height:210px;border-radius:14px;background:linear-gradient(120deg,#1e3a5f,#2563eb 60%,#60a5fa);position:relative;overflow:hidden;margin-bottom:20px;display:flex;align-items:center;padding:32px 40px;cursor:pointer;transition:filter .2s;}
31	.banner:hover{filter:brightness(1.06);}
32	.banner h2{font-size:24px;font-weight:900;color:#fff;line-height:1.3;letter-spacing:-0.03em;margin-bottom:6px;}
33	.banner p{font-size:12px;color:rgba(255,255,255,.75);margin-bottom:14px;line-height:1.6;}
34	.banner-cta{display:inline-block;background:rgba(255,255,255,.2);border:1px solid rgba(255,255,255,.4);color:#fff;border-radius:20px;padding:6px 18px;font-size:11px;font-weight:700;}
35	.banner-deco{position:absolute;right:40px;top:50%;transform:translateY(-50%);font-size:80px;opacity:.13;}
36	.banner-hint{position:absolute;bottom:14px;right:20px;font-size:10px;color:rgba(255,255,255,.5);}
37	
38	.sec-hdr{display:flex;align-items:center;gap:8px;margin-bottom:14px;}
39	.sec-hdr h3{font-size:15px;font-weight:700;color:#0a1628;}
40	
41	.prod-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;}
42	.prod-card{background:#fff;border:1px solid #e8e8e8;border-radius:12px;overflow:hidden;cursor:pointer;transition:box-shadow .2s,transform .15s;}
43	.prod-card:hover{box-shadow:0 6px 20px rgba(26,86,219,.1);transform:translateY(-2px);}
44	.pc-img{position:relative;height:155px;background:#000;overflow:hidden;}
45	.pc-img img{width:100%;height:100%;object-fit:contain;}
46	.pc-tag{position:absolute;top:8px;left:8px;font-size:9px;font-weight:700;border-radius:4px;padding:2px 6px;}
47	.tag-k{background:rgba(26,86,219,.25);color:#60a5fa;border:1px solid rgba(96,165,250,.4);}
48	.tag-i{background:rgba(255,152,0,.2);color:#fbbf24;border:1px solid rgba(251,191,36,.4);}
49	.tag-h{background:rgba(40,199,111,.2);color:#34d399;border:1px solid rgba(52,211,153,.4);}
50	.pc-btns{position:absolute;bottom:8px;left:0;right:0;display:flex;gap:5px;padding:0 8px;}
51	.pc-btn{flex:1;background:rgba(255,255,255,.9);border:none;border-radius:5px;padding:5px;font-size:10px;font-weight:600;cursor:pointer;font-family:inherit;}
52	.pc-info{padding:9px 11px 11px;}
53	.pc-brand{font-size:10px;color:#aaa;margin-bottom:1px;}
54	.pc-name{font-size:12px;font-weight:700;color:#0a1628;margin-bottom:3px;line-height:1.35;}
55	.pc-spec{font-size:10px;color:#999;margin-bottom:5px;}
56	.pc-price{font-size:14px;font-weight:900;color:#0a1628;}
57	
58	.rg-top{padding:18px 14px;border-bottom:1px solid #f0f0f0;display:flex;align-items:center;gap:10px;}
59	.rg-av{width:40px;height:40px;border-radius:50%;background:#e2e8f0;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;}
60	.rg-name{font-size:13px;font-weight:700;color:#475569;}
61	.rg-hint{font-size:11px;color:#94a3b8;margin-top:2px;line-height:1.5;}
62	.rg-login{margin:12px;background:linear-gradient(90deg,#1a56db,#5a8dee);border:none;border-radius:8px;padding:10px;color:#fff;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit;width:calc(100% - 24px);}
63	.rg-jt{padding:12px 14px 6px;font-size:12px;font-weight:700;color:#0a1628;}
64	.rg-empty{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:24px 14px;gap:8px;color:#94a3b8;}
65	.rg-empty-ico{font-size:26px;opacity:.4;}
66	.rg-empty-txt{font-size:11px;text-align:center;line-height:1.5;}
67	.rg-btm{margin-top:auto;padding:10px 12px;border-top:1px solid #f0f0f0;display:grid;grid-template-columns:repeat(4,1fr);gap:4px;}
68	.rg-ico{display:flex;flex-direction:column;align-items:center;gap:3px;cursor:pointer;padding:6px 2px;border-radius:8px;transition:background .15s;}
69	.rg-ico:hover{background:#f0f4ff;}
70	.rg-ico-box{width:30px;height:30px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:14px;}
71	.rg-ico-lbl{font-size:9px;color:#555;text-align:center;line-height:1.3;}
72	
73	.fab-btn{position:fixed;bottom:28px;right:28px;width:56px;height:56px;border-radius:50%;background:linear-gradient(135deg,#7b2ff7,#b44cff);border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:24px;box-shadow:0 4px 20px rgba(123,47,247,.45);z-index:100;transition:transform .2s;}
74	.fab-btn:hover{transform:scale(1.08);}
75	.fab-label{position:fixed;bottom:35px;right:92px;background:rgba(20,20,30,.85);color:#fff;font-size:12px;font-weight:600;border-radius:22px;padding:8px 16px;white-space:nowrap;z-index:100;cursor:pointer;}
76	
77	.backdrop{position:fixed;inset:0;background:rgba(0,0,0,.38);z-index:150;opacity:0;pointer-events:none;transition:opacity .3s;}
78	.backdrop.on{opacity:1;pointer-events:all;}
79	
80	.chat-panel{position:fixed;right:-760px;top:0;width:760px;height:100vh;background:#fff;z-index:200;display:flex;box-shadow:-6px 0 40px rgba(0,0,0,.18);transition:right .38s cubic-bezier(.4,0,.2,1);}
81	.chat-panel.open{right:0;}
82	
83	.cl{flex:1;display:flex;flex-direction:column;min-width:0;}
84	.cl-top{padding:14px 20px;border-bottom:1px solid #f0f0f0;display:flex;align-items:center;gap:12px;flex-shrink:0;}
85	.cl-av{width:38px;height:38px;border-radius:50%;background:linear-gradient(135deg,#7b2ff7,#b44cff);display:flex;align-items:center;justify-content:center;font-size:17px;color:#fff;flex-shrink:0;}
86	.cl-name{font-size:14px;font-weight:700;}
87	.cl-status{display:flex;align-items:center;gap:5px;margin-top:2px;}
88	.sdot{width:7px;height:7px;border-radius:50%;background:#22c55e;animation:pulse 2s infinite;}
89	@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
90	.stxt{font-size:10px;color:#22c55e;font-weight:600;}
91	.cl-close{margin-left:auto;background:none;border:none;font-size:20px;cursor:pointer;color:#aaa;padding:4px 6px;border-radius:6px;}
92	.cl-close:hover{background:#f5f5f5;color:#555;}
93	
94	/* 프로그레스 바 */
95	.cl-progress{padding:10px 20px 0;display:flex;gap:6px;flex-shrink:0;}
96	.prog-step{flex:1;height:3px;border-radius:2px;background:#e2e8f0;transition:background .4s;}
97	.prog-step.done{background:#7b2ff7;}
98	.prog-step.active{background:linear-gradient(90deg,#7b2ff7,#b44cff);}
99	.prog-label{font-size:10px;color:#94a3b8;padding:4px 20px 8px;display:flex;justify-content:space-between;}
100	.prog-label span{flex:1;text-align:center;}
101	.prog-label span.cur{color:#7b2ff7;font-weight:700;}
102	
103	.cl-body{flex:1;overflow-y:auto;padding:20px;display:flex;flex-direction:column;gap:16px;}
104	
105	.msg{display:flex;gap:10px;}
106	.m-av{width:34px;height:34px;border-radius:50%;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:15px;align-self:flex-start;margin-top:2px;}
107	.av-bot{background:linear-gradient(135deg,#7b2ff7,#b44cff);color:#fff;}
108	.av-usr{background:linear-gradient(135deg,#1a56db,#5a8dee);color:#fff;}
109	.msg-r{display:flex;flex-direction:column;gap:3px;max-width:80%;}
110	.msg-user{flex-direction:row-reverse;}
111	.msg-user .msg-r{align-items:flex-end;}
112	.bubble{padding:11px 15px;border-radius:16px;font-size:13px;line-height:1.7;}
113	.b-bot{background:#f0f2ff;color:#1a1a2e;border-bottom-left-radius:4px;}
114	.b-usr{background:linear-gradient(135deg,#1a56db,#3b6fd4);color:#fff;border-bottom-right-radius:4px;}
115	.m-time{font-size:10px;color:#c0c4cc;padding:0 4px;}
116	
117	/* 조건 태그 — 사용자 답변에 붙는 뱃지 */
118	.cond-tag{display:inline-flex;align-items:center;gap:5px;background:rgba(255,255,255,.22);border:1px solid rgba(255,255,255,.4);border-radius:12px;padding:2px 10px;font-size:11px;font-weight:700;margin-top:4px;}
119	
120	.typing-row{display:flex;gap:10px;align-items:flex-start;}
121	.typing-bub{padding:12px 16px;background:#f0f2ff;border-radius:16px;border-bottom-left-radius:4px;display:flex;gap:5px;align-items:center;}
122	.typing-bub span{width:7px;height:7px;border-radius:50%;background:#7b2ff7;opacity:.6;animation:bounce .9s infinite;}
123	.typing-bub span:nth-child(2){animation-delay:.18s;}
124	.typing-bub span:nth-child(3){animation-delay:.36s;}
125	@keyframes bounce{0%,60%,100%{transform:translateY(0)}30%{transform:translateY(-8px)}}
126	
127	/* 수집된 조건 요약 박스 */
128	.cond-summary{background:linear-gradient(135deg,#f5f3ff,#eef2ff);border:1px solid #ddd6fe;border-radius:12px;padding:12px 14px;font-size:12px;line-height:1.8;}
129	.cond-summary .cs-title{font-size:11px;font-weight:700;color:#7b2ff7;margin-bottom:6px;}
130	.cond-row{display:flex;align-items:center;gap:6px;color:#374151;}
131	.cond-ico{width:18px;text-align:center;}
132	.cond-val{font-weight:700;color:#1a1a2e;}
133	
134	/* 추천 카드 */
135	.rec-wrap{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:8px;}
136	.rc{background:#fff;border:1px solid #dde3f8;border-radius:10px;overflow:hidden;cursor:pointer;transition:box-shadow .15s,transform .15s;}
137	.rc:hover{box-shadow:0 3px 14px rgba(26,86,219,.15);transform:translateY(-1px);}
138	.rc-img{height:100px;background:#000;overflow:hidden;}
139	.rc-img img{width:100%;height:100%;object-fit:contain;}
140	.rc-info{padding:8px 10px 10px;}
141	.rc-brand{font-size:9px;color:#aaa;margin-bottom:1px;}
142	.rc-name{font-size:11px;font-weight:700;color:#0a1628;line-height:1.35;margin-bottom:2px;}
143	.rc-spec{font-size:9px;color:#999;margin-bottom:4px;}
144	.rc-price{font-size:12px;font-weight:900;color:#1a56db;margin-bottom:5px;}
145	.rc-btn{width:100%;background:#1a56db;color:#fff;border:none;border-radius:5px;padding:5px 0;font-size:10px;font-weight:700;cursor:pointer;font-family:inherit;}
146	.rc-btn:hover{background:#1648c2;}
147	
148	.cl-input{padding:12px 18px;border-top:1px solid #f0f0f0;display:flex;gap:10px;align-items:center;flex-shrink:0;}
149	.cl-input input{flex:1;border:1.5px solid #e2e8f0;border-radius:24px;padding:10px 18px;font-size:13px;font-family:inherit;outline:none;transition:border .15s;background:#f5f5f8;color:#aaa;}
150	.cl-send{width:40px;height:40px;border-radius:50%;background:#e2e8f0;border:none;display:flex;align-items:center;justify-content:center;color:#aaa;font-size:17px;flex-shrink:0;}

