### 1. **HTML Structure for Comparison View (두 사용자 결과 동시 표시)**

When both A and B users are selected and applied, the comparison renders in a 2-column layout:

```html
<div class="sec-row">
  <div>
    <div class="sec-label">
      <span class="badge badge-a">딥러닝 추천</span>
      <span style="font-size:15px">✨</span>
      <span class="sec-title"><span class="name-a">홍길동</span>님을 위한 인공지능 추천 신차</span>
    </div>
    <div class="car-grid">
      [User A's cars cards here]
    </div>
  </div>

  <div>
    <div class="sec-label">
      <span class="badge badge-b">딥러닝 추천</span>
      <span style="font-size:15px">✨</span>
      <span class="sec-title"><span class="name-b">이순신</span>님을 위한 인공지능 추천 신차</span>
    </div>
    <div class="car-grid">
      [User B's cars cards here]
    </div>
  </div>
</div>
```

### 2. **CSS Classes for Comparison Layout**

**Main comparison container:**
```css
.sec-row { 
  display: grid; 
  grid-template-columns: 1fr 1fr;  /* Two equal columns */
  gap: 14px;                        /* Gap between columns */
}
```

**Section labels and badges:**
```css
.sec-label { 
  display: flex; 
  align-items: center; 
  gap: 7px; 
  margin-bottom: 10px; 
}

.badge { 
  color: #fff; 
  font-size: 10px; 
  font-weight: 700; 
  border-radius: 4px; 
  padding: 2px 8px; 
}

.badge-a { 
  background: linear-gradient(90deg,#1a56db,#5a8dee);  /* Blue gradient for User A */
}

.badge-b { 
  background: linear-gradient(90deg,#28c76f,#48d98a);  /* Green gradient for User B */
}

.sec-title { 
  font-size: 13px; 
  font-weight: 700; 
}

.name-a { 
  color: #1a56db;  /* Blue for User A's name */
}

.name-b { 
  color: #28c76f;  /* Green for User B's name */
}
```

**Car card grid (used in both columns):**
```css
.car-grid { 
  display: grid; 
  grid-template-columns: 1fr 1fr;  /* 2-column card layout within each user section */
  gap: 10px; 
}

.car-card { 
  background: #fff; 
  border: 1px solid #e8e8e8; 
  border-radius: 10px; 
  overflow: hidden; 
  cursor: pointer; 
  transition: box-shadow .2s, transform .15s; 
}

.car-card:hover { 
  box-shadow: 0 4px 18px rgba(26,86,219,.13); 
  transform: translateY(-2px); 
}
```

### 3. **JavaScript Rendering Logic for Comparison**

The comparison is controlled by the `renderMain()` function:

```javascript
let curUser = 'A', curTab = '검색', compareMode = false;

function renderMain() {
  const d = DATA[curUser];
  const cmpKey = curUser === 'A' ? 'B' : 'A';
  const cmp = compareMode ? DATA[cmpKey] : null;

  let html = `
    <div class="banner" style="background:${d.banner.grad}">
      <div class="banner-txt">
        <h2>${d.banner.title}</h2>
        <p>${d.banner.sub}</p>
        <span class="banner-badge">${d.banner.badge}</span>
      </div>
      <div class="banner-deco">${d.banner.deco}</div>
    </div>`;

  if (cmp) {
    // 2-column compare mode - renders BOTH users side-by-side
    html += `<div class="sec-row">
      ${renderBlock(d, 'A')}
      ${renderBlock(cmp, 'B')}
    </div>`;
  } else {
    // Single user mode
    html += renderBlock(d, curUser);
  }

  document.getElementById('mainContent').innerHTML = html;
}

function renderBlock(d, key) {
  const badgeC = key === 'A' ? 'badge-a' : 'badge-b';
  const nameC  = key === 'A' ? 'name-a'  : 'name-b';

  let cards = d.cars.map(c => `
    <div class="car-card">
      <div class="car-img">
        <img src="${CAR_IMGS[c.img]}" alt="${c.brand}" loading="lazy">
        <span class="img-tag ${c.tagC}">${c.tag}</span>
        <div class="img-btns">
          <button class="ib" onclick="wish(this)">♡ 찜하기</button>
          <button class="ib">🛒 담기</button>
        </div>
      </div>
      <div class="car-info">
        <div class="car-brand">${c.brand}</div>
        <div class="car-name">${c.name}</div>
        <div class="car-spec">${c.spec}</div>
        <div class="price-row"><span class="price">${c.price}</span><span class="price-unit">원~</span></div>
        <div class="price-sub">${c.sub}</div>
      </div>
    </div>`).join('');

  return `<div>
    <div class="sec-label">
      <span class="badge ${badgeC}">딥러닝 추천</span>
      <span style="font-size:15px">✨</span>
      <span class="sec-title"><span class="${nameC}">${d.name}</span>님을 위한 인공지능 추천 신차</span>
    </div>
    <div class="car-grid">${cards}</div>
  </div>`;
}
```

**Comparison activation (User Selection):**
```javascript
function onSelectA(v) { 
  curUser = v;  // Set base user (A or B)
}

function onSelectB(v) { 
  compareMode = (v !== 'none');  // Enable compare when user B is selected
}

function apply() {
  renderMain();
  renderSidebar();
}
```

### 4. **Empty State / "No Results" UI**

The file doesn't show a "검색 결과 없음" (no results) state in the main view, but there IS an empty state for the journey list in the sidebar:

```javascript
function renderJourney() {
  const items = DATA[curUser].journey[curTab] || [];
  const list = document.getElementById('jList');
  if (!items.length) { 
    list.innerHTML = '<div style="padding:18px;text-align:center;color:#ccc;font-size:12px">기록 없음</div>'; 
    return; 
  }
  // ... render items
}
```

### 5. **Search Suggestion Chips/Keywords UI (Journey Items)**

The journey/search history is rendered as tag chips with emojis and categories:

```html
<div class="j-item">
  <div class="j-thumb">${i.e}</div>  <!-- Emoji icon -->
  <div>
    <span class="j-tag">${curTab}</span>  <!-- Category badge -->
    <div class="j-name">${i.n}</div>     <!-- Suggestion name -->
    <div class="j-cat">${i.c}</div>      <!-- Category path -->
  </div>
</div>
```

**CSS for suggestion chips:**
```css
.j-item { 
  display: flex; 
  gap: 8px; 
  padding: 7px 0; 
  border-bottom: 1px solid #f5f5f5; 
  align-items: flex-start; 
}

.j-thumb { 
  width: 38px; 
  height: 38px; 
  border-radius: 6px; 
  background: #f0f4ff; 
  display: flex; 
  align-items: center; 
  justify-content: center; 
  font-size: 18px; 
  flex-shrink: 0; 
}

.j-tag { 
  font-size: 9px; 
  font-weight: 700; 
  background: #eef2ff; 
  color: #1a56db; 
  border-radius: 3px; 
  padding: 1px 5px; 
  margin-bottom: 2px; 
  display: inline-block; 
}

.j-name { 
  font-size: 11px; 
  font-weight: 600; 
  color: #333; 
}

.j-cat { 
  font-size: 10px; 
  color: #bbb; 
}
```

**Example data structure for suggestions:**
```javascript
journey:{
  '검색':[
    {e:'🔍', n:'G80 주행성능 세단', c:'세단 > 대형 > 고성능'},
    {e:'🔍', n:'BMW 5시리즈 530i', c:'세단 > 수입 > 중대형'},
    {e:'🔍', n:'제네시스 세단 비교', c:'브랜드 비교'}
  ],
  '클릭':[...],
  '찜':[...]
}
```

### Key Layout Behavior

- **Single user mode**: Shows full-width banner + results for current user
- **Comparison mode**: Shows same banner (from user A) + side-by-side `.sec-row` with two `.renderBlock()` outputs
- **Color coding**: Blue (#1a56db) for User A, Green (#28c76f) for User B
- **Navigation**: Top bar dropdown selects base user (기준), comparison user (비교), and "적용" button triggers render

