/**
 * 검색 결과 표시 (복수 결과셋)
 * 비교 모드 시 좌우 sec-row 레이아웃으로 렌더링
 */
function displaySearchResults(matches) {
  const resultsContainer = document.getElementById('search-results-container');
  if (!resultsContainer) { console.error('검색 결과 컨테이너 없음'); return; }

  const recommendedSection = document.getElementById('recommended-section');
  if (recommendedSection) recommendedSection.style.display = 'none';

  // 비교 모드 판별 (member.js의 전역변수 참조)
  const isCompare = (typeof compareUser !== 'undefined' && compareUser !== 'none'
                     && typeof currentUser !== 'undefined' && currentUser !== 'C'
                     && compareUser !== currentUser);

  resultsContainer.innerHTML = '';
  resultsContainer.style.display = 'block';

  // 총 결과 건수 계산
  const totalCars = matches.reduce((sum, m) => {
    const rd = (typeof SEARCH_RESULTS !== 'undefined') && SEARCH_RESULTS[m.id];
    return sum + (rd ? rd.cars.length : 0);
  }, 0);

  // 건수 바 렌더링
  resultsContainer.insertAdjacentHTML('beforeend', `
    <div class="sr-count-bar">
      <span class="sr-count-badge">${totalCars}건</span>
      <span class="sr-count-label">검색 결과</span>
      ${isCompare ? '<span class="sr-compare-badge">🔀 비교 모드</span>' : ''}
    </div>
  `);

  // 각 결과셋 렌더링
  for (const match of matches) {
    if (isCompare) {
      const dataA = (typeof SEARCH_RESULTS !== 'undefined') && SEARCH_RESULTS[match.id];
      const dataB = (typeof COMPARE_SEARCH_RESULTS !== 'undefined') && COMPARE_SEARCH_RESULTS[match.id];
      if (dataA || dataB) {
        resultsContainer.appendChild(createCompareSearchSection(dataA, dataB));
      }
    } else {
      if (typeof SEARCH_RESULTS !== 'undefined' && SEARCH_RESULTS[match.id]) {
        resultsContainer.appendChild(createSearchResultSection(SEARCH_RESULTS[match.id], match.score));
      }
    }
  }
}

