/**
 * 공통 유틸리티 및 이미지 관리
 * member.html, non_member.html에서 로드됨
 */

// ============================================
// 이미지 경로 관리
// ============================================

const CAR_IMGS = {
  g80:      '../assets/images/g80.png',
  bmw5:     '../assets/images/bmw5.png',
  k8:       '../assets/images/k8.png',
  grandeur: '../assets/images/grandeur.png',
  sorento:  '../assets/images/sorento.png',
  tucson:   '../assets/images/tucson.png',
  nx350h:   '../assets/images/nx350h.png',
  santafe:  '../assets/images/santafe.png',
};

// ============================================
// 자연어 검색 기능
// ============================================

let searchQueries = [];
let searchDebounceTimer = null;

/**
 * 검색 초기화 - 페이지 로드 시 실행
 * search_data.js에서 로드된 데이터 사용
 */
function initSearch() {
  // search_data.js에서 SEARCH_QUERIES를 전역으로 제공
  if (typeof SEARCH_QUERIES !== 'undefined') {
    searchQueries = SEARCH_QUERIES;
    console.log('검색 질의 로드됨:', searchQueries.length, '개');
    return true;
  } else {
    console.error('SEARCH_QUERIES 데이터를 찾을 수 없습니다. search_data.js가 로드되었나요?');
    return false;
  }
}

/**
 * 검색 입력 핸들러 (디바운스 적용)
 */
function handleSearchInput(inputValue) {
  clearTimeout(searchDebounceTimer);

  searchDebounceTimer = setTimeout(() => {
    performSearch(inputValue);
  }, 500); // 0.5초 디바운스
}

/**
 * 검색 수행
 */
async function performSearch(query) {
  const cleanQuery = query.trim().toLowerCase();

  // 빈 검색: 기본 상태로 복귀
  if (!cleanQuery) {
    showDefaultResults();
    return;
  }

  // 키워드 토크나이즈
  const keywords = cleanQuery.split(/\s+/);

  // 각 질의와 매칭 점수 계산
  const matches = searchQueries.map(q => {
    const intersection = keywords.filter(k =>
      q.keywords.some(qk => qk.includes(k) || k.includes(qk.substring(0, 2)))
    );
    return {
      ...q,
      score: intersection.length
    };
  }).filter(m => m.score > 0);

  // 점수 높은 순으로 정렬
  matches.sort((a, b) => b.score - a.score);

  if (matches.length === 0) {
    showNoResults(keywords);
  } else {
    await displaySearchResults(matches);
  }
}

/**
 * 검색 결과 표시 (복수 결과셋)
 * 비교 모드 시 좌우 sec-row 레이아웃으로 렌더링
 */
function displaySearchResults(matches) {
  const resultsContainer = document.getElementById('search-results-container');
  if (!resultsContainer) { console.error('검색 결과 컨테이너 없음'); return; }

  const recommendedSection = document.getElementById('recommended-section');
  if (recommendedSection) recommendedSection.style.display = 'none';

  // 비교 모드 판별 (member.js의 전역변수 참조)
  const isCompare = (typeof compareUser !== 'undefined' && compareUser !== 'none'
                     && typeof currentUser !== 'undefined' && currentUser !== 'C'
                     && compareUser !== currentUser);

  resultsContainer.innerHTML = '';
  resultsContainer.style.display = 'block';

  // 총 결과 건수 계산
  const totalCars = matches.reduce((sum, m) => {
    const rd = (typeof SEARCH_RESULTS !== 'undefined') && SEARCH_RESULTS[m.id];
    return sum + (rd ? rd.cars.length : 0);
  }, 0);

  // 건수 바 렌더링
  resultsContainer.insertAdjacentHTML('beforeend', `
    <div class="sr-count-bar">
      <span class="sr-count-badge">${totalCars}건</span>
      <span class="sr-count-label">검색 결과</span>
      ${isCompare ? '<span class="sr-compare-badge">🔀 비교 모드</span>' : ''}
    </div>
  `);

  // 각 결과셋 렌더링
  for (const match of matches) {
    if (isCompare) {
      const dataA = (typeof SEARCH_RESULTS !== 'undefined') && SEARCH_RESULTS[match.id];
      const dataB = (typeof COMPARE_SEARCH_RESULTS !== 'undefined') && COMPARE_SEARCH_RESULTS[match.id];
      if (dataA || dataB) {
        resultsContainer.appendChild(createCompareSearchSection(dataA, dataB));
      }
    } else {
      if (typeof SEARCH_RESULTS !== 'undefined' && SEARCH_RESULTS[match.id]) {
        resultsContainer.appendChild(createSearchResultSection(SEARCH_RESULTS[match.id], match.score));
      }
    }
  }
}

/**
 * 단일 사용자 검색결과 섹션 HTML 생성 (car-grid 2열 형식)
 */
function createSearchResultSection(resultData, score) {
  const section = document.createElement('div');
  section.className = 'search-result-section';
  section.innerHTML = `
    <div class="sr-section-header">
      <span class="badge badge-search">AI 추천</span>
      <span class="sr-section-title">${resultData.title}</span>
      <span class="sr-section-desc">${resultData.description}</span>
    </div>
    <div class="car-grid" id="search-grid-${resultData.queryId}">
      ${resultData.cars.map(car => `
        <div class="car-card" onclick="viewDetails('${car.img}')">
          <div class="car-img">
            <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
            <span class="img-tag ${car.tagC}">${car.tag}</span>
            <div class="img-btns">
              <button class="ib" onclick="viewDetails('${car.img}'); event.stopPropagation();">상세</button>
              <button class="ib" onclick="selectProduct('${car.img}'); event.stopPropagation();">선택</button>
            </div>
          </div>
          <div class="car-info">
            <div class="car-brand">${car.brand}</div>
            <div class="car-name">${car.name}</div>
            <div class="car-spec">${car.spec}</div>
            <div class="price-row"><span class="price">${car.price}</span></div>
            <div class="price-sub">${car.sub}</div>
            <div style="font-size:10px;color:#1a56db;margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
          </div>
        </div>
      `).join('')}
    </div>
  `;
  return section;
}

/**
 * 비교 모드 검색결과 섹션 (좌우 sec-row 2열)
 */
function createCompareSearchSection(dataA, dataB) {
  const section = document.createElement('div');
  section.className = 'search-result-section';
  const blockA = dataA ? renderSearchBlock(dataA, currentUser) : '<div style="color:#ccc;font-size:12px;padding:20px;text-align:center;">결과 없음</div>';
  const blockB = dataB ? renderSearchBlock(dataB, compareUser) : '<div style="color:#ccc;font-size:12px;padding:20px;text-align:center;">결과 없음</div>';
  section.innerHTML = `<div class="sec-row">${blockA}${blockB}</div>`;
  return section;
}

/**
 * 비교 모드 개별 사용자 블록 HTML
 */
function renderSearchBlock(resultData, userKey) {
  const badgeC = userKey === 'A' ? 'badge-a' : 'badge-b';
  const nameC  = userKey === 'A' ? 'name-a'  : 'name-b';
  const userName = (typeof DATA !== 'undefined' && DATA[userKey]) ? DATA[userKey].name : (userKey + '사용자');
  const priceColor = userKey === 'A' ? '#1a56db' : '#28c76f';

  const cards = resultData.cars.map(car => `
    <div class="car-card" onclick="viewDetails('${car.img}')">
      <div class="car-img">
        <img src="${CAR_IMGS[car.img]}" alt="${car.brand}" style="max-width:100%; max-height:100%; object-fit:contain;">
        <span class="img-tag ${car.tagC}">${car.tag}</span>
        <div class="img-btns">
          <button class="ib" onclick="viewDetails('${car.img}');event.stopPropagation();">상세</button>
          <button class="ib" onclick="selectProduct('${car.img}');event.stopPropagation();">선택</button>
        </div>
      </div>
      <div class="car-info">
        <div class="car-brand">${car.brand}</div>
        <div class="car-name">${car.name}</div>
        <div class="car-spec">${car.spec}</div>
        <div class="price-row"><span class="price" style="color:${priceColor}">${car.price}</span></div>
        <div class="price-sub">${car.sub}</div>
        <div style="font-size:10px;color:${priceColor};margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
      </div>
    </div>
  `).join('');

  return `<div>
    <div class="sec-label">
      <span class="badge ${badgeC}">AI 추천</span>
      <span class="sec-title"><span class="${nameC}">${userName}</span>님 · ${resultData.description}</span>
    </div>
    <div class="car-grid">${cards}</div>
  </div>`;
}

/**
 * 검색 결과 없음 표시
 */
function showNoResults(keywords) {
  const resultsContainer = document.getElementById('search-results-container');

  if (!resultsContainer) return;

  const recommendedSection = document.getElementById('recommended-section');
  if (recommendedSection) {
    recommendedSection.style.display = 'none';
  }

  resultsContainer.innerHTML = `
    <div class="search-no-result">
      <div class="no-result-icon">🔍</div>
      <div class="no-result-text">"${keywords.join(' ')}"에 맞는 검색 결과가 없습니다.</div>
      <div class="no-result-subtitle">다른 검색어를 시도해보세요.</div>
      <div class="search-suggestions">
        <div class="suggestion-title">추천 검색어:</div>
        <div class="suggestion-chips">
          ${searchQueries.map(q => `
            <div class="suggestion-chip" onclick="document.querySelector('#search-input').value='${q.label}'; handleSearchInput('${q.label}')">
              ${q.description}
            </div>
          `).join('')}
        </div>
      </div>
    </div>
  `;

  resultsContainer.style.display = 'block';
}

/**
 * 기본 상태로 복귀 (검색창 비움)
 */
function showDefaultResults() {
  const resultsContainer = document.getElementById('search-results-container');
  const recommendedSection = document.getElementById('recommended-section');

  if (resultsContainer) {
    resultsContainer.style.display = 'none';
  }

  if (recommendedSection) {
    recommendedSection.style.display = 'block';
  }
}

